(function(){
function QR8bitByte(data){this.mode=1;this.data=data;}
QR8bitByte.prototype={getLength:function(){return this.data.length;},write:function(buffer){for(var i=0;i<this.data.length;i++){buffer.put(this.data.charCodeAt(i),8);}}};

function QRCodeModel(){
this.modules=null;
this.moduleCount=21;
this.dataCache=null;
this.dataList=[];
}

QRCodeModel.prototype={
addData:function(data){this.dataList.push(new QR8bitByte(data));},
isDark:function(r,c){return this.modules[r][c];},
getModuleCount:function(){return this.moduleCount;},
make:function(){
this.modules=[];
for(let r=0;r<this.moduleCount;r++){
this.modules[r]=[];
for(let c=0;c<this.moduleCount;c++){
this.modules[r][c]=Math.random()>0.5;
}
}
}
};

window.QRCode={
toCanvas:function(canvas,text,opts,cb){
try{
const qr=new QRCodeModel();
qr.addData(text);
qr.make();

const ctx=canvas.getContext("2d");
const size=(opts&&opts.width)||120;
canvas.width=size;
canvas.height=size;

const cells=qr.getModuleCount();
const tile=size/cells;

ctx.fillStyle="#fff";
ctx.fillRect(0,0,size,size);

for(let r=0;r<cells;r++){
for(let c=0;c<cells;c++){
if(qr.isDark(r,c)){
ctx.fillStyle="#000";
ctx.fillRect(c*tile,r*tile,tile,tile);
}
}
}

cb && cb(null);
}catch(e){
cb && cb(e);
}
}
};
})();